import React from 'react';
import { Dialog } from 'primereact/dialog';

function NotificationsPanel({ visible, onHide }) {
  return (
    <Dialog
      visible={visible}
      onHide={onHide}
      style={{ width: '406px', height: '336px' }}
      header="Уведомления"
      draggable={false}
      resizable={false}
      headerStyle={{ 
        padding: '1.5rem',
        borderBottom: 'none'
      }}
      contentStyle={{ 
        padding: '0 1.5rem 1.5rem 1.5rem',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'flex-start',
        justifyContent: 'flex-start'
      }}
    >
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column',
        gap: '8px',
        width: '100%'
      }}>
        <p style={{ 
          fontSize: '16px', 
          fontWeight: '400', 
          color: '#94a3b8',
          margin: 0,
          lineHeight: '1.5'
        }}>
          Список уведомлений пуст...
        </p>
        <p style={{ 
          fontSize: '16px', 
          fontWeight: '400', 
          color: '#94a3b8',
          margin: 0,
          lineHeight: '1.5'
        }}>
          загляните позже, вдруг что-нибудь появится
        </p>
      </div>
    </Dialog>
  );
}

export default NotificationsPanel;
